    payload = {
        "client_name": client_name,
        "account_id": account_id,
        "platform": platform,
        "working_session": {
            "tasks": tasks
        },
        "timeout": 3600,
        "auth_token": "3a9c5d4e7f8b1236e45a7c9f0b1d2e3f"
