    response = requests.post(
        url,
        json=payload,
        headers={"Content-Type": "application/json"}
    )

    if response.status_code == 200:
        print("Success! Session ID:", response.json()["session_id"])
        print("Tasks executed:", response.json()["completed_tasks"])
